<Stats id="monster-drake_flame_drake--stats" atts={[21,13,16,9,12,10]} bab={6} cmb={12} cmd={23} feats={["Flyby Attack","Improved Initiative","Power Attack"]} skills={{"fly":{"b":8},"intm":{"b":9},"per":{"b":10}}} lang={["D"]} sq="speed surge" />
