<Stats id="monster-drake_sea_drake--stats" atts={[23,15,18,8,10,9]} bab={7} cmb={14} cmd={26} feats={["Improved Initiative","Lightning Reflexes","Power Attack",["Skill Focus"," (Stealth)"]]} skills={{"fly":{"b":10}}} lang={["D"]} sq={<><Link to="/umr/amphibious">amphibious</Link>, speed surge</>} />
